// Identify categories (folders) and template file
  // Note: mimeType not available, so we identify by name patterns
  const items = $input.all();

  const categories = [];
  let templateFileId = null;

  for (const item of items) {
    const name = item.json.name || '';
    const id = item.json.id;

    // Template file ends with .html and contains 'template'
    if (name.toLowerCase().includes('template') && name.endsWith('.html')) {
      templateFileId = id;
      console.log('Found template:', name);
    }
    // Category folders don't have file extensions
    else if (!name.includes('.')) {
      categories.push({
        categoryName: name.toLowerCase().replace(/\s+/g, '_'),
        categoryFolderId: id
      });
      console.log('Found category:', name);
    }
  }

  console.log('Total categories:', categories.length);
  console.log('Template ID:', templateFileId);

  // Return first category for simplified version
  if (categories.length > 0) {
    return [{
      json: {
        ...categories[0],
        templateFileId
      }
    }];
  }

  return [];

const item = $input.first();

// Read template from filesystem binary storage
const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
const templateHtml = buffer.toString('utf8');

// Get category info from previous node
const categoryInfo = $('Identify Category & Template').first().json;

return [{
  json: {
    categoryName: categoryInfo.categoryName,
    categoryFolderId: categoryInfo.categoryFolderId,
    templateHtml
  }
}];

// Get only the LATEST date folder
const items = $input.all();
const categoryInfo = $('Store Template').first().json;

// Filter to date folders (YYYY-MM-DD pattern) and sort descending
const dateFolders = items
  .filter(item => /^\d{4}-\d{2}-\d{2}$/.test(item.json.name))
  .map(item => ({
    dateFolderId: item.json.id,
    dateFolderName: item.json.name
  }))
  .sort((a, b) => b.dateFolderName.localeCompare(a.dateFolderName));

console.log('Date folders found:', dateFolders.length);
console.log('Latest:', dateFolders[0]?.dateFolderName);

// Return only the latest one
if (dateFolders.length > 0) {
  return [{
    json: {
      ...categoryInfo,
      ...dateFolders[0]
    }
  }];
}

return [];

// Identify P2 and P3 file IDs
const items = $input.all();
const context = $('Get Latest Date Only').first().json;

let p2FileId = null;
let p3FileId = null;

for (const item of items) {
  const name = (item.json.name || '').toLowerCase();
  const id = item.json.id;

  if (name.includes('p2') || name.includes('market')) {
    p2FileId = id;
    console.log('Found P2:', name);
  }
  if (name.includes('p3') || name.includes('competitor')) {
    p3FileId = id;
    console.log('Found P3:', name);
  }
}

console.log('P2 ID:', p2FileId);
console.log('P3 ID:', p3FileId);

return [{
  json: {
    ...context,
    p2FileId,
    p3FileId,
    hasP2: !!p2FileId,
    hasP3: !!p3FileId
  }
}];

// Rename binary key from 'data' to 'p2_binary' to avoid merge conflicts
const items = $input.all();

return items.map(item => {
  const newItem = {
    json: { ...item.json },
    binary: {}
  };

  if (item.binary?.data) {
    newItem.binary.p2_binary = item.binary.data;
    console.log('Renamed P2 binary, size:', item.binary.data.data?.length || 0);
  }

  return newItem;
});

// Rename binary key from 'data' to 'p3_binary' to avoid merge conflicts
const items = $input.all();

