// ================================================================
// PARSE P2 & P3 REPORTS - Complete Extraction
// ================================================================

const cheerio = require('cheerio');
const item = $input.first();

// Get context from earlier nodes
const context = $('Identify P2 & P3 Files').first().json;

// Extract binary content
let p2Html = '';
let p3Html = '';

console.log('Binary keys available:', Object.keys(item.binary || {}));

if (item.binary?.p2_binary) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'p2_binary');
  p2Html = buffer.toString('utf8');
}

if (item.binary?.p3_binary) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'p3_binary');
  p3Html = buffer.toString('utf8');
}

// ================================================================
// PARSE P2 (Market Trend Report)
// ================================================================
let p2Data = {
  keyInsight: '',
  marketMetrics: { size2025: '', size2033: '', cagr: '' },
  microSegments: [],
  colorPalette: [],
  risks: [],
  recommendations: [],
  moodboardImages: [],
  attributeBars: { materials: [], sizes: [], colors: [], prices: [] }
};

try {
  if (p2Html) {
    const $p2 = cheerio.load(p2Html);

    // Key Insight
    p2Data.keyInsight = $p2('.key-insight p').first().text().trim() ||
                        $p2('.summary-hero .key-insight p').first().text().trim() ||
                        $p2('.executive-summary p').first().text().trim();
    console.log('P2 Key Insight:', p2Data.keyInsight.substring(0, 100));

    // Market Metrics - look for profile-card elements
    $p2('.profile-card').each((i, el) => {
      const heading = $p2(el).find('h4').text().toLowerCase();
      const value = $p2(el).find('p').first().text().trim();

      if (heading.includes('market size') && heading.includes('2025')) {
        p2Data.marketMetrics.size2025 = value;
      } else if (heading.includes('projected') && heading.includes('2033')) {
        p2Data.marketMetrics.size2033 = value;
      } else if (heading.includes('cagr')) {
        p2Data.marketMetrics.cagr = value;
      }
    });
    console.log('P2 Market Metrics:', JSON.stringify(p2Data.marketMetrics));

    // Micro-Segments
    $p2('.segment-card').each((i, el) => {
      const name = $p2(el).find('h4').first().text().trim();
      const tier = $p2(el).find('.segment-badge').text().trim();
      const description = $p2(el).find('.segment-description, p').first().text().trim();
      const metaText = $p2(el).find('.segment-meta').text();

      // Extract colors and use cases from meta
      const colorsMatch = metaText.match(/🎨\s*([^🏠]+)/);
      const useCasesMatch = metaText.match(/🏠\s*(.+)/);

      if (name) {
        p2Data.microSegments.push({
          name: name.replace(/^\d+\.\s*/, ''),
          tier: tier || 'Emerging',
          description: description.substring(0, 300),
          colors: colorsMatch?.[1]?.trim() || '',
          useCases: useCasesMatch?.[1]?.trim() || ''
        });
      }
    });
    console.log('P2 Segments found:', p2Data.microSegments.length);

    // Color Palette
    $p2('.color-swatch, .color-card').each((i, el) => {
      const style = $p2(el).attr('style') || '';
      const innerStyle = $p2(el).find('[style*="background"]').attr('style') || '';
      const allStyles = style + ' ' + innerStyle;
      const hexMatch = allStyles.match(/#[A-Fa-f0-9]{6}/);
      const name = $p2(el).find('.swatch-label, .color-name').text().trim() || 
                   $p2(el).text().trim().split('\n')[0];

      if (hexMatch && p2Data.colorPalette.length < 6) {
        p2Data.colorPalette.push({
          hex: hexMatch[0],
          name: name.substring(0, 30) || `Color ${i + 1}`
        });
      }
    });
    console.log('P2 Colors found:', p2Data.colorPalette.length);

    // Risks
    $p2('.risk-card').each((i, el) => {
      const title = $p2(el).find('h4, .risk-title').first().text().trim();
      const className = $p2(el).attr('class') || '';
      let severity = 'medium';
      if (className.includes('high') || className.includes('risk-high')) severity = 'high';
      else if (className.includes('low') || className.includes('risk-low')) severity = 'low';

      const description = $p2(el).find('p, .risk-description').first().text().trim();
      const mitigation = $p2(el).find('.risk-mitigation').text().replace(/Mitigation:?/gi, '').trim();

      if (title) {
        p2Data.risks.push({ title, severity, description: description.substring(0, 200), mitigation });
      }
    });
    console.log('P2 Risks found:', p2Data.risks.length);

    // Recommendations
    $p2('.rec-item, .recommendation-card').each((i, el) => {
      const title = $p2(el).find('h4, strong').first().text().trim();
      const description = $p2(el).find('p').first().text().trim();
      const impact = $p2(el).find('.rec-impact').text().trim();

      if (title && p2Data.recommendations.length < 5) {
        p2Data.recommendations.push({ title, description: description.substring(0, 200), impact });
      }
    });
    console.log('P2 Recommendations found:', p2Data.recommendations.length);

    // Moodboard Images (base64)
    $p2('img').each((i, el) => {
      const src = $p2(el).attr('src');
      if (src?.startsWith('data:image') && p2Data.moodboardImages.length < 4) {
        p2Data.moodboardImages.push(src);
      }
    });
    console.log('P2 Moodboard images found:', p2Data.moodboardImages.length);

  // Attribute Distribution Bars - FIXED selectors
  $p2('.attribute-card').each((i, card) => {
    const cardTitle = $p2(card).find('h3').first().text().toLowerCase();
    const bars = [];

    $p2(card).find('.data-row').each((j, row) => {
      const label = $p2(row).find('.label').text().trim();
      const value = $p2(row).find('.value').text().trim();
      const barStyle = $p2(row).find('.bar').attr('style') || '';
      const widthMatch = barStyle.match(/([\d.]+)%/);

      if (label) {
        bars.push({
          label,
          value: value || '',
          width: widthMatch ? parseFloat(widthMatch[1]) : 0
        });
      }
    });

    if (cardTitle.includes('material')) {
      p2Data.attributeBars.materials = bars;
    } else if (cardTitle.includes('size')) {
      p2Data.attributeBars.sizes = bars;
    } else if (cardTitle.includes('color') || cardTitle.includes('pattern')) {
      p2Data.attributeBars.colors = bars;
    } else if (cardTitle.includes('price')) {
      p2Data.attributeBars.prices = bars;
    }
  });
  console.log('P2 Attribute bars - materials:', p2Data.attributeBars.materials.length,
              ', sizes:', p2Data.attributeBars.sizes.length,
              ', colors:', p2Data.attributeBars.colors.length);
  }
} catch (e) {
  console.error('P2 Parse Error:', e.message);
}

// ================================================================
// PARSE P3 (Competitor Analysis Report)
// ================================================================
let p3Data = {
  keyInsight: '',
  scope: { amazonProducts: 0, walmartProducts: 0, wayfairProducts: 0 },
  pricePositioning: {
    wayfair: { avg: '', min: '', max: '' },
    amazon: { avg: '', min: '', max: '' },
    walmart: { avg: '', min: '', max: '' }
  },
  comparisonTable: [],
  priceBands: { budget: {}, mid: {}, premium: {} },
  priceGaps: [],
  opportunities: [],
  quickWins: [],
  strategicInitiatives: [],
  suppliers: [],
  discountTiers: []
};

try {
  if (p3Html) {
    const $p3 = cheerio.load(p3Html);

    // Key Insight
    p3Data.keyInsight = $p3('.key-insight p').first().text().trim();
    console.log('P3 Key Insight:', p3Data.keyInsight.substring(0, 100));

    // Scope - Product Counts
    const scopeText = $p3('.scope-card, .scope-section').text();
    const amazonMatch = scopeText.match(/Amazon[^\d]*(\d+)/i);
    const walmartMatch = scopeText.match(/Walmart[^\d]*(\d+)/i);
    const wayfairMatch = scopeText.match(/Wayfair[^\d]*(\d+)/i);
    if (amazonMatch) p3Data.scope.amazonProducts = parseInt(amazonMatch[1]);
    if (walmartMatch) p3Data.scope.walmartProducts = parseInt(walmartMatch[1]);
    if (wayfairMatch) p3Data.scope.wayfairProducts = parseInt(wayfairMatch[1]);
    console.log('P3 Scope:', JSON.stringify(p3Data.scope));

    // Price Positioning - from comparison table
    $p3('.comparison-table tbody tr').each((i, row) => {
      const cells = $p3(row).find('td');
      const attribute = $p3(cells[0]).text().toLowerCase();

      if (attribute.includes('price')) {
        // Parse Wayfair prices
        const wayfairText = $p3(cells[1]).text();
        const wayfairAvg = wayfairText.match(/Avg:\s*\$([\d,.]+)/i);
        const wayfairMin = wayfairText.match(/Min:\s*\$([\d,.]+)/i);
        const wayfairMax = wayfairText.match(/Max:\s*\$([\d,.]+)/i);
        if (wayfairAvg) p3Data.pricePositioning.wayfair.avg = '$' + wayfairAvg[1];
        if (wayfairMin) p3Data.pricePositioning.wayfair.min = '$' + wayfairMin[1];
        if (wayfairMax) p3Data.pricePositioning.wayfair.max = '$' + wayfairMax[1];

        // Parse Amazon prices
        const amazonText = $p3(cells[2]).text();
        const amazonAvg = amazonText.match(/Avg:\s*\$([\d,.]+)/i);
        const amazonMin = amazonText.match(/Min:\s*\$([\d,.]+)/i);
        const amazonMax = amazonText.match(/Max:\s*\$([\d,.]+)/i);
        if (amazonAvg) p3Data.pricePositioning.amazon.avg = '$' + amazonAvg[1];
        if (amazonMin) p3Data.pricePositioning.amazon.min = '$' + amazonMin[1];
        if (amazonMax) p3Data.pricePositioning.amazon.max = '$' + amazonMax[1];

        // Parse Walmart prices
        const walmartText = $p3(cells[3]).text();
        const walmartAvg = walmartText.match(/Avg:\s*\$([\d,.]+)/i);
        const walmartMin = walmartText.match(/Min:\s*\$([\d,.]+)/i);
        const walmartMax = walmartText.match(/Max:\s*\$([\d,.]+)/i);
        if (walmartAvg) p3Data.pricePositioning.walmart.avg = '$' + walmartAvg[1];
        if (walmartMin) p3Data.pricePositioning.walmart.min = '$' + walmartMin[1];
        if (walmartMax) p3Data.pricePositioning.walmart.max = '$' + walmartMax[1];
      }
    });
    console.log('P3 Price Positioning:', JSON.stringify(p3Data.pricePositioning));

    // Comparison Table
    $p3('.comparison-table tbody tr').each((i, row) => {
      const cells = $p3(row).find('td');
      if (cells.length >= 5) {
        const attribute = $p3(cells[0]).text().trim();
        const wayfair = $p3(cells[1]).text().trim().substring(0, 200);
        const amazon = $p3(cells[2]).text().trim().substring(0, 200);
        const walmart = $p3(cells[3]).text().trim().substring(0, 200);
        const winner = $p3(cells[4]).text().trim();

        if (attribute) {
          p3Data.comparisonTable.push({ attribute, wayfair, amazon, walmart, winner });
        }
      }
    });
    console.log('P3 Comparison rows:', p3Data.comparisonTable.length);

    // Price Bands
    $p3('.band').each((i, el) => {
      const text = $p3(el).text();
      const values = text.match(/W:\s*(\d+)\s*\|\s*A:\s*(\d+)\s*\|\s*Wm:\s*(\d+)/i);

      if (text.toLowerCase().includes('budget') && values) {
        p3Data.priceBands.budget = { wayfair: values[1], amazon: values[2], walmart: values[3] };
      } else if (text.toLowerCase().includes('mid') && values) {
        p3Data.priceBands.mid = { wayfair: values[1], amazon: values[2], walmart: values[3] };
      } else if (text.toLowerCase().includes('premium') && values) {
        p3Data.priceBands.premium = { wayfair: values[1], amazon: values[2], walmart: values[3] };
      }
    });
    console.log('P3 Price Bands:', JSON.stringify(p3Data.priceBands));

    // Price Gaps Heatmap
    $p3('.gap').each((i, el) => {
      const range = $p3(el).find('span').first().text().trim();
      const description = $p3(el).find('span').last().text().trim();
      const className = $p3(el).attr('class') || '';
      let level = 'moderate';
      if (className.includes('hot')) level = 'hot';
      else if (className.includes('warm')) level = 'warm';
      else if (className.includes('cool') || className.includes('open')) level = 'open';

      if (range) {
        p3Data.priceGaps.push({ range, description, level });
      }
    });
    console.log('P3 Price Gaps:', p3Data.priceGaps.length);

    // Opportunities
    $p3('.whitespace-opportunities .opportunity-card, .opportunity-cards .opportunity-card').each((i, el) => {
      const title = $p3(el).find('h4').text().replace(/[🎯⚡📊💡🔥]/g, '').trim();
      const description = $p3(el).find('p').first().text().trim();
      const className = $p3(el).attr('class') || '';
      const priority = className.includes('high') ? 'high' : (className.includes('low') ? 'low' : 'medium');

      if (title && p3Data.opportunities.length < 6) {
        p3Data.opportunities.push({ title, description: description.substring(0, 250), priority });
      }
    });
    console.log('P3 Opportunities:', p3Data.opportunities.length);

    // Quick Wins
    $p3('.quick-wins .rec-card').each((i, el) => {
      const title = $p3(el).find('h4').text().replace(/^\d+\.\s*/, '').trim();
      const description = $p3(el).find('p').first().text().trim();
      const priority = $p3(el).attr('class')?.includes('high') ? 'high' : 'medium';

      if (title) {
        p3Data.quickWins.push({ title, description: description.substring(0, 200), priority });
      }
    });
    console.log('P3 Quick Wins:', p3Data.quickWins.length);

    // Strategic Initiatives
    $p3('.strategic-plays .rec-card, .strategic-initiatives .rec-card').each((i, el) => {
      const title = $p3(el).find('h4').text().replace(/^\d+\.\s*/, '').trim();
      const description = $p3(el).find('p').first().text().trim();
      const priority = $p3(el).attr('class')?.includes('high') ? 'high' : 'medium';

      if (title) {
        p3Data.strategicInitiatives.push({ title, description: description.substring(0, 200), priority });
      }
    });
    console.log('P3 Strategic Initiatives:', p3Data.strategicInitiatives.length);

    // Suppliers
    $p3('.supplier-identification table tbody tr, .suppliers-observed table tbody tr').each((i, row) => {
      const cells = $p3(row).find('td');
      if (cells.length >= 4) {
        const name = $p3(cells[0]).text().trim();
        const platform = $p3(cells[1]).text().trim();

        // Skip if it looks like a product row
        if (name.length > 50 || platform.startsWith('$')) return;

        if (name && p3Data.suppliers.length < 10) {
          p3Data.suppliers.push({
            name,
            platform,
            knownFor: $p3(cells[2]).text().trim().substring(0, 100),
            priceRange: $p3(cells[3]).text().trim(),
            website: $p3(cells[4])?.find('a').attr('href') || ''
          });
        }
      }
    });
    console.log('P3 Suppliers:', p3Data.suppliers.length);

    // Discount Tiers
    $p3('.discount-tier').each((i, el) => {
      const label = $p3(el).find('span').first().text().trim();
      const values = $p3(el).find('span').last().text().trim();
      const match = values.match(/W:\s*(\d+)\s*\|\s*Wm:\s*(\d+)/i);

      if (label && match) {
        p3Data.discountTiers.push({
          label,
          wayfair: parseInt(match[1]),
          walmart: parseInt(match[2])
        });
      }
    });
    console.log('P3 Discount Tiers:', p3Data.discountTiers.length);
  }
} catch (e) {
  console.error('P3 Parse Error:', e.message);
}

// Return combined data
return [{
  json: {
    categoryName: context.categoryName,
    dateFolderName: context.dateFolderName,
    templateHtml: context.templateHtml,
    p2Data,
    p3Data
  }
}];

// ================================================================
// BUILD COMPLETE DASHBOARD HTML
// ================================================================

const data = $input.first().json;
const { categoryName, dateFolderName, templateHtml, p2Data, p3Data } = data;

let html = templateHtml;

// Helper function for safe replacement
const replace = (placeholder, value) => {
  html = html.replace(new RegExp(placeholder.replace(/[{}]/g, '\\$&'), 'g'), value || '');
};

// ================================================================
// BASIC INFO
// ================================================================
const categoryTitle = categoryName.replace(/_/g, ' ').replace(/\b\w/g, l => l.toUpperCase());
replace('{{CATEGORY_TITLE}}', categoryTitle);
replace('{{CATEGORY_NAME}}', categoryTitle);
replace('{{REPORT_DATE}}', dateFolderName);
replace('{{GENERATED_AT}}', new Date().toISOString().split('T')[0]);

// Product counts
const amazonProducts = p3Data.scope.amazonProducts || 0;
const walmartProducts = p3Data.scope.walmartProducts || 0;
const wayfairProducts = p3Data.scope.wayfairProducts || 0;
const totalProducts = amazonProducts + walmartProducts + wayfairProducts;

replace('{{AMAZON_PRODUCTS}}', amazonProducts.toString());
replace('{{WALMART_PRODUCTS}}', walmartProducts.toString());
replace('{{WAYFAIR_PRODUCTS}}', wayfairProducts.toString());
replace('{{TOTAL_PRODUCTS}}', totalProducts.toString());

// ================================================================
// KEY INSIGHTS
// ================================================================
replace('{{TREND_KEY_INSIGHT}}', p2Data.keyInsight || 'Market trend data not available.');
replace('{{COMPETITIVE_KEY_INSIGHT}}', p3Data.keyInsight || 'Competitive analysis data not available.');

// ================================================================
// MARKET METRICS (P2)
// ================================================================
replace('{{MARKET_SIZE_2025}}', p2Data.marketMetrics.size2025 || 'N/A');
replace('{{MARKET_SIZE_2033}}', p2Data.marketMetrics.size2033 || 'N/A');
replace('{{MARKET_CAGR}}', p2Data.marketMetrics.cagr || 'N/A');

// ================================================================
// TARGET SEGMENT (First segment from P2)
// ================================================================
const targetSegment = p2Data.microSegments[0] || {};
replace('{{TARGET_SEGMENT_NAME}}', targetSegment.name || 'Emerging Segment');
replace('{{TARGET_SEGMENT_TIER}}', targetSegment.tier || 'Tier 1');
replace('{{TARGET_SEGMENT_USE_CASES}}', targetSegment.useCases || 'Various applications');

// ================================================================
// PRICE POSITIONING (P3)
// ================================================================
replace('{{WAYFAIR_AVG_PRICE}}', p3Data.pricePositioning.wayfair.avg || 'N/A');
replace('{{WAYFAIR_MIN_PRICE}}', p3Data.pricePositioning.wayfair.min || 'N/A');
replace('{{WAYFAIR_MAX_PRICE}}', p3Data.pricePositioning.wayfair.max || 'N/A');
replace('{{AMAZON_AVG_PRICE}}', p3Data.pricePositioning.amazon.avg || 'N/A');
replace('{{AMAZON_MIN_PRICE}}', p3Data.pricePositioning.amazon.min || 'N/A');
replace('{{AMAZON_MAX_PRICE}}', p3Data.pricePositioning.amazon.max || 'N/A');
replace('{{WALMART_AVG_PRICE}}', p3Data.pricePositioning.walmart.avg || 'N/A');
replace('{{WALMART_MIN_PRICE}}', p3Data.pricePositioning.walmart.min || 'N/A');
replace('{{WALMART_MAX_PRICE}}', p3Data.pricePositioning.walmart.max || 'N/A');

// ================================================================
// PRICE BANDS (P3)
// ================================================================
replace('{{BUDGET_WAYFAIR}}', p3Data.priceBands.budget?.wayfair || '0');
replace('{{BUDGET_AMAZON}}', p3Data.priceBands.budget?.amazon || '0');
replace('{{BUDGET_WALMART}}', p3Data.priceBands.budget?.walmart || '0');
replace('{{MID_WAYFAIR}}', p3Data.priceBands.mid?.wayfair || '0');
replace('{{MID_AMAZON}}', p3Data.priceBands.mid?.amazon || '0');
replace('{{MID_WALMART}}', p3Data.priceBands.mid?.walmart || '0');
replace('{{PREMIUM_WAYFAIR}}', p3Data.priceBands.premium?.wayfair || '0');
replace('{{PREMIUM_AMAZON}}', p3Data.priceBands.premium?.amazon || '0');
replace('{{PREMIUM_WALMART}}', p3Data.priceBands.premium?.walmart || '0');

// ================================================================
// RISK COUNTS (P2)
// ================================================================
