  const searchUrl = platformClass === 'amazon' 
    ? `https://www.amazon.com/s?k=${encodeURIComponent(supplier.name)}` 
    : platformClass === 'walmart' 
      ? `https://www.walmart.com/search?q=${encodeURIComponent(supplier.name)}`
      : `https://www.wayfair.com/keyword.html?keyword=${encodeURIComponent(supplier.name)}`;
  supplierChipsHtml += `<a href="${searchUrl}" target="_blank" class="supplier-card"><span class="supplier-name">${supplier.name}</span><span class="platform ${platformClass}">${supplier.platform}</span></a>`;
});
