const buildBarsHtml = (bars) => {
  if (!bars || bars.length === 0) return '<p class="empty-state">No data available</p>';
  return bars.map(bar => `
    <div class="bar-item">
      <div class="bar-label">${bar.label}</div>
      <div class="bar-track">
        <div class="bar-fill" style="width: ${bar.width}%;"></div>
      </div>
      <div class="bar-value">${bar.value}</div>
    </div>`).join('');
};

