// Prepare HTML for download as binary file
const { html, fileName } = $input.first().json;

const buffer = Buffer.from(html, 'utf8');
const binaryData = {
  data: buffer.toString('base64'),
  mimeType: 'text/html',
  fileName: fileName
};

return [{
  json: { fileName },
  binary: { data: binaryData }
}];
